    wire [4:0] synd_4_gf = {synd_4_4, synd_4_3, synd_4_2, synd_4_1, synd_4_0};
    wire [4:0] synd_5_gf = {synd_5_4, synd_5_3, synd_5_2, synd_5_1, synd_5_0};
    wire [4:0] synd_6_gf = {synd_6_4, synd_6_3, synd_6_2, synd_6_1, synd_6_0};
    wire [29:0] synd_bus;
    assign synd_bus = {synd_6_4, synd_6_3, synd_6_2, synd_6_1, synd_6_0, synd_5_4, synd_5_3, synd_5_2, synd_5_1, synd_5_0, synd_4_4, synd_4_3, synd_4_2, synd_4_1, synd_4_0, synd_3_4, synd_3_3, synd_3_2, synd_3_1, synd_3_0, synd_2_4, synd_2_3, synd_2_2, synd_2_1, synd_2_0, synd_1_4, synd_1_3, synd_1_2, synd_1_1, synd_1_0};
    wire any_syndrome = |synd_bus;
    localparam [1:0] ST_IDLE=2'd0, ST_BM=2'd1, ST_CHIEN=2'd2, ST_DONE=2'd3;
    reg [1:0] state;
    localparam integer BM_SIZE = 10;
    reg [4:0] bm_c [0:BM_SIZE-1];
    reg [4:0] bm_b [0:BM_SIZE-1];
    reg [4:0] bm_bval, bm_coef, bm_coef_latched;
    reg [4:0] bm_L, bm_mreg;
    reg [3:0] bm_step;
    reg [4:0] syn_reg [0:5];
    reg [4:0] lambda [0:3];
    reg [2:0] lambda_deg;
    reg [30:0] err_mask;
    reg [5:0] chien_pos;
    reg [30:0] corrected_cw;
    wire [4:0] bm_syn_m1;
    assign bm_syn_m1 = (bm_step >= 1) ? syn_reg[bm_step - 1] : 5'd0;
    wire [4:0] bm_prod1;
    gf_mul_w5 u_bm_p1 (.a(bm_c[1]), .b(bm_syn_m1), .y(bm_prod1));
    wire [4:0] bm_syn_m2;
    assign bm_syn_m2 = (bm_step >= 2) ? syn_reg[bm_step - 2] : 5'd0;
    wire [4:0] bm_prod2;
    gf_mul_w5 u_bm_p2 (.a(bm_c[2]), .b(bm_syn_m2), .y(bm_prod2));
    wire [4:0] bm_syn_m3;
    assign bm_syn_m3 = (bm_step >= 3) ? syn_reg[bm_step - 3] : 5'd0;
    wire [4:0] bm_prod3;
    gf_mul_w5 u_bm_p3 (.a(bm_c[3]), .b(bm_syn_m3), .y(bm_prod3));
    wire [4:0] bm_d_comb = syn_reg[bm_step] ^ ((bm_L >= 1) ? bm_prod1 : 5'd0) ^ ((bm_L >= 2) ? bm_prod2 : 5'd0) ^ ((bm_L >= 3) ? bm_prod3 : 5'd0);
    reg bm_c_busy, bm_upd_arm, bm_swap_pending;
    reg [4:0] bm_new_bval;
    reg [4:0] bm_t [0:BM_SIZE-1];  // t_poly = C before update (for swap)
    wire [4:0] bm_inv;
    gf_inv_w5 u_bm_inv (.a(bm_bval), .y(bm_inv));
    gf_mul_w5 u_bm_coef (.a(bm_d_comb), .b(bm_inv), .y(bm_coef));
    wire [4:0] bm_upd;
    reg [3:0] upd_i;
    gf_mul_w5 u_bm_upd (.a(bm_coef_latched), .b(bm_b[upd_i]), .y(bm_upd));
    reg [5:0] alpha_inv_rom [0:62];
    initial begin
        alpha_inv_rom[0] = 5'd1;
        alpha_inv_rom[1] = 5'd18;
        alpha_inv_rom[2] = 5'd9;
        alpha_inv_rom[3] = 5'd22;
        alpha_inv_rom[4] = 5'd11;
        alpha_inv_rom[5] = 5'd23;
        alpha_inv_rom[6] = 5'd25;
        alpha_inv_rom[7] = 5'd30;
        alpha_inv_rom[8] = 5'd15;
        alpha_inv_rom[9] = 5'd21;
        alpha_inv_rom[10] = 5'd24;
        alpha_inv_rom[11] = 5'd12;
        alpha_inv_rom[12] = 5'd6;
        alpha_inv_rom[13] = 5'd3;
        alpha_inv_rom[14] = 5'd19;
        alpha_inv_rom[15] = 5'd27;
        alpha_inv_rom[16] = 5'd31;
        alpha_inv_rom[17] = 5'd29;
        alpha_inv_rom[18] = 5'd28;
        alpha_inv_rom[19] = 5'd14;
        alpha_inv_rom[20] = 5'd7;
        alpha_inv_rom[21] = 5'd17;
        alpha_inv_rom[22] = 5'd26;
        alpha_inv_rom[23] = 5'd13;
        alpha_inv_rom[24] = 5'd20;
        alpha_inv_rom[25] = 5'd10;
        alpha_inv_rom[26] = 5'd5;
        alpha_inv_rom[27] = 5'd16;
        alpha_inv_rom[28] = 5'd8;
        alpha_inv_rom[29] = 5'd4;
        alpha_inv_rom[30] = 5'd2;
    end
    wire [4:0] chien_X = alpha_inv_rom[chien_pos];
    wire [4:0] chien_h3;
    assign chien_h3 = lambda[3];
    wire [4:0] chien_p2, chien_h2;
    gf_mul_w5 u_chien_p2 (.a(chien_h3), .b(chien_X), .y(chien_p2));
    assign chien_h2 = chien_p2 ^ lambda[2];
    wire [4:0] chien_p1, chien_h1;
    gf_mul_w5 u_chien_p1 (.a(chien_h2), .b(chien_X), .y(chien_p1));
    assign chien_h1 = chien_p1 ^ lambda[1];
    wire [4:0] chien_p0, chien_h0;
    gf_mul_w5 u_chien_p0 (.a(chien_h1), .b(chien_X), .y(chien_p0));
    assign chien_h0 = chien_p0 ^ lambda[0];
    wire [4:0] chien_eval;
    assign chien_eval = chien_h0;
    wire chien_is_root = (lambda_deg == 3'd0) ? (lambda[0] == 5'd0) : (chien_eval == 5'd0);
    wire [30:0] chien_flip = chien_is_root ? (31'd1 << chien_pos) : 31'd0;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= ST_IDLE; valid_out <= 1'b0;
            error_detected <= 1'b0; error_corrected <= 1'b0;
            codeword_out <= 31'd0; data_out <= 16'd0;
            err_mask <= 31'd0; bm_step <= 4'd0; chien_pos <= 6'd0;
            upd_i <= 4'd0; bm_coef_latched <= 5'd0;
            bm_c_busy <= 1'b0; bm_upd_arm <= 1'b0; bm_swap_pending <= 1'b0;
            bm_L <= 5'd0; bm_mreg <= 5'd1; bm_bval <= 5'd1;
            lambda[0] <= 5'd0;
            lambda[1] <= 5'd0;
            lambda[2] <= 5'd0;
            lambda[3] <= 5'd0;
            lambda_deg <= 3'd0;
        end else begin
            valid_out <= 1'b0;
            if (encode_en) begin
                codeword_out <= {data_k, parity};
                data_out <= 16'd0;
                error_detected <= 1'b0; error_corrected <= 1'b0;
                valid_out <= 1'b1; state <= ST_IDLE;
            end else if (decode_en && state == ST_IDLE) begin
                corrected_cw <= codeword_in; err_mask <= 31'd0;
                syn_reg[0] <= synd_1_gf;
                syn_reg[1] <= synd_2_gf;
                syn_reg[2] <= synd_3_gf;
                syn_reg[3] <= synd_4_gf;
                syn_reg[4] <= synd_5_gf;
                syn_reg[5] <= synd_6_gf;
                lambda[0] <= 5'd0;
                lambda[1] <= 5'd0;
                lambda[2] <= 5'd0;
                lambda[3] <= 5'd0;
                lambda_deg <= 3'd0;
                bm_c[0] <= 5'd1;
                bm_c[1] <= 5'd0;
                bm_c[2] <= 5'd0;
                bm_c[3] <= 5'd0;
                bm_c[4] <= 5'd0;
                bm_c[5] <= 5'd0;
                bm_c[6] <= 5'd0;
                bm_c[7] <= 5'd0;
                bm_c[8] <= 5'd0;
                bm_c[9] <= 5'd0;
                bm_b[0] <= 5'd1;
                bm_b[1] <= 5'd0;
                bm_b[2] <= 5'd0;
                bm_b[3] <= 5'd0;
                bm_b[4] <= 5'd0;
                bm_b[5] <= 5'd0;
                bm_b[6] <= 5'd0;
                bm_b[7] <= 5'd0;
                bm_b[8] <= 5'd0;
                bm_b[9] <= 5'd0;
                bm_bval <= 5'd1; bm_L <= 5'd0; bm_mreg <= 5'd1; bm_step <= 4'd0;
                chien_pos <= 6'd0; upd_i <= 4'd0; bm_coef_latched <= 5'd0;
                bm_c_busy <= 1'b0; bm_upd_arm <= 1'b0; bm_swap_pending <= 1'b0;
                state <= any_syndrome ? ST_BM : ST_DONE;
                error_detected <= any_syndrome; error_corrected <= 1'b0;
            end else case (state)
                ST_BM: begin
                    if (bm_c_busy) begin
                        if (!bm_upd_arm) begin
                            bm_coef_latched <= bm_coef;
                            upd_i <= 4'd0;
                            bm_upd_arm <= 1'b1;
                        end else if (upd_i < BM_SIZE) begin
                            if (bm_b[upd_i] != 5'd0 && (upd_i + bm_mreg) < BM_SIZE)
                                bm_c[upd_i + bm_mreg] <= bm_c[upd_i + bm_mreg] ^ bm_upd;
                            upd_i <= upd_i + 4'd1;
                        end else begin
                            upd_i <= 4'd0;
                            bm_c_busy <= 1'b0; bm_upd_arm <= 1'b0;
                            if (bm_swap_pending) begin
                                bm_b[0] <= bm_t[0];
                                bm_b[1] <= bm_t[1];
                                bm_b[2] <= bm_t[2];
                                bm_b[3] <= bm_t[3];
                                bm_b[4] <= bm_t[4];
                                bm_b[5] <= bm_t[5];
                                bm_b[6] <= bm_t[6];
                                bm_b[7] <= bm_t[7];
                                bm_b[8] <= bm_t[8];
                                bm_b[9] <= bm_t[9];
                                bm_bval <= bm_new_bval;
                                bm_mreg <= 5'd1;
                                bm_swap_pending <= 1'b0;
                            end else bm_mreg <= bm_mreg + 5'd1;
                            if (bm_step == 5) begin
                            lambda[0] <= bm_c[0];
                            lambda[1] <= bm_c[1];
                            lambda[2] <= bm_c[2];
                            lambda[3] <= bm_c[3];
                            lambda_deg <= (bm_L > 3) ? 3'd3 : bm_L[2:0];
                            state <= ST_CHIEN; chien_pos <= 6'd0;
                            end else bm_step <= bm_step + 4'd1;
                        end
                    end else begin
                        if (bm_d_comb == 5'd0) begin
                            bm_mreg <= bm_mreg + 5'd1;
                            if (bm_step == 5) begin
                            lambda[0] <= bm_c[0];
                            lambda[1] <= bm_c[1];
                            lambda[2] <= bm_c[2];
                            lambda[3] <= bm_c[3];
                            lambda_deg <= (bm_L > 3) ? 3'd3 : bm_L[2:0];
                            state <= ST_CHIEN; chien_pos <= 6'd0;
                            end else bm_step <= bm_step + 4'd1;
                        end else begin
                                bm_t[0] <= bm_c[0];
                                bm_t[1] <= bm_c[1];
                                bm_t[2] <= bm_c[2];
                                bm_t[3] <= bm_c[3];
                                bm_t[4] <= bm_c[4];
                                bm_t[5] <= bm_c[5];
                                bm_t[6] <= bm_c[6];
                                bm_t[7] <= bm_c[7];
                                bm_t[8] <= bm_c[8];
                                bm_t[9] <= bm_c[9];
                            upd_i <= 4'd0; bm_c_busy <= 1'b1; bm_upd_arm <= 1'b0;
                            if ((bm_L << 1) <= bm_step) begin
                                bm_L <= bm_step + 5'd1 - bm_L;
                                bm_new_bval <= bm_d_comb;
                                bm_swap_pending <= 1'b1;
                            end
                        end
                    end
                end
                ST_CHIEN: begin
                    if (chien_is_root)
                        err_mask <= err_mask | chien_flip;
                    if (chien_pos == 6'd62) begin
                        corrected_cw <= codeword_in ^ err_mask ^ chien_flip;
                        state <= ST_DONE;
                    end else chien_pos <= chien_pos + 6'd1;
                end
                ST_DONE: begin
                    data_out <= corrected_cw[30:15];
                    codeword_out <= corrected_cw;
                    error_corrected <= any_syndrome; valid_out <= 1'b1;
                    state <= ST_IDLE;
                end
                default: state <= ST_IDLE;
            endcase
        end
    end
endmodule
